-- =====================================================
-- 用户协议和隐私协议单页数据
-- 在"服务协议"分类下插入用户协议和隐私协议页面
-- tpl 标识供前端按 tpl 参数查询
-- 执行时间: 2026-07-17
-- =====================================================

-- 确保"服务协议"分类存在
SET @agreement_cat_id = (SELECT `id` FROM `advn_singlepage_category` WHERE `name` = '服务协议' AND `deletetime` IS NULL LIMIT 1);

INSERT INTO `advn_singlepage_category` (`name`, `description`, `weigh`, `status`, `createtime`, `updatetime`)
SELECT '服务协议', '服务条款和隐私协议', 80, 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
FROM DUAL
WHERE NOT EXISTS (SELECT 1 FROM `advn_singlepage_category` WHERE `name` = '服务协议' AND `deletetime` IS NULL);

SET @agreement_cat_id = (SELECT `id` FROM `advn_singlepage_category` WHERE `name` = '服务协议' AND `deletetime` IS NULL LIMIT 1);

-- 删除已有的同名页面（避免重复）
DELETE FROM `advn_singlepage` WHERE `tpl` IN ('user-agreement', 'privacy-policy') AND `category_id` = @agreement_cat_id;

-- =====================================================
-- 用户协议
-- =====================================================
INSERT INTO `advn_singlepage` (
  `category_id`, `title`, `keywords`, `description`,
  `image`, `content`, `tpl`, `weigh`, `status`,
  `createtime`, `updatetime`
) VALUES (
  @agreement_cat_id,
  '用户协议',
  '用户协议,服务条款,使用条款,注册协议',
  '平台用户服务协议',
  '',
  '<h2 style="text-align:center;color:#E62129;">用户服务协议</h2>\n<p style="text-align:center;color:#999;font-size:12px;">更新日期：2026年7月17日</p>\n<p><br/></p>\n<p><b>尊敬的用户，欢迎使用本平台！</b></p>\n<p>在您使用本平台提供的各项服务之前，请您仔细阅读并充分理解本《用户服务协议》（以下简称"本协议"）。您一旦注册、登录、使用本平台服务，即视为您已阅读并同意本协议的全部内容。</p>\n<p><br/></p>\n<h3 style="color:#333;">一、总则</h3>\n<p>1.1 本协议是您与平台运营方（以下简称"平台"）之间关于使用平台各项服务所订立的协议。</p>\n<p>1.2 平台有权根据法律法规变化及业务发展需要，对本协议进行修订。修订后的协议将在平台内公布，若您继续使用平台服务，即视为同意修订后的协议。</p>\n<p>1.3 本协议中与您的权益密切相关的条款，已采用加粗等方式显著标识，请您特别注意。</p>\n<p><br/></p>\n<h3 style="color:#333;">二、账号注册与管理</h3>\n<p>2.1 您需使用真实手机号或微信授权等方式注册账号，并对账号信息的真实性、合法性负责。</p>\n<p>2.2 每位用户仅可注册一个账号，禁止一人多号、虚假注册。</p>\n<p>2.3 您应妥善保管账号和密码，因您自身原因导致账号被盗、密码泄露等，由您自行承担责任。</p>\n<p>2.4 您不得将账号出借、转让、出售给他人使用。</p>\n<p>2.5 如发现账号被他人冒用或存在安全风险，请立即联系平台客服。</p>\n<p><br/></p>\n<h3 style="color:#333;">三、用户行为规范</h3>\n<p>3.1 您在使用平台服务时，应遵守国家法律法规，不得利用平台从事违法违规活动。</p>\n<p>3.2 <b>禁止行为包括但不限于：</b></p>\n<ul>\n<li>使用模拟器、脚本、外挂、自动化工具等作弊手段获取金币或奖励；</li>\n<li>利用系统漏洞获取不当利益；</li>\n<li>恶意刷金币、刷提现、虚假签到等行为；</li>\n<li>发布违法违规、虚假、侵权、恶意的内容；</li>\n<li>干扰平台正常运营，影响其他用户使用；</li>\n<li>同一设备或IP注册多个账号；</li>\n<li>使用VPN、代理等手段规避平台风控规则。</li>\n</ul>\n<p>3.3 如您违反上述规定，平台有权视情节轻重采取以下措施：</p>\n<ul>\n<li>警告、限制功能（如冻结提现）；</li>\n<li>冻结账号；</li>\n<li>永久封禁账号；</li>\n<li>扣除违规所得金币/佣金；</li>\n<li>依法追究法律责任。</li>\n</ul>\n<p><br/></p>\n<h3 style="color:#333;">四、金币与奖励</h3>\n<p>4.1 平台金币为虚拟权益，仅限在本平台内使用，不可转让、兑换现金或提现至第三方账户。</p>\n<p>4.2 金币获取方式包括但不限于：每日签到、观看视频、邀请好友、红包活动等，具体规则以平台公告为准。</p>\n<p>4.3 平台有权根据运营需要调整金币获取规则、兑换比例及每日上限，调整前将通过公告通知。</p>\n<p>4.4 <b>金币提现规则：</b></p>\n<ul>\n<li>金币可按平台公示的兑换比例兑换为人民币，提现至微信零钱；</li>\n<li>最低提现金额及每日提现次数限制以平台设置为准；</li>\n<li>新注册用户需满足注册天数要求后方可提现；</li>\n<li>提现审核通过后，金额将在合理时间内到账；</li>\n<li>平台有权对异常提现申请进行审核或拒绝。</li>\n</ul>\n<p><br/></p>\n<h3 style="color:#333;">五、分销与邀请</h3>\n<p>5.1 用户可通过邀请码、邀请链接等方式邀请好友注册，获得邀请奖励和分销佣金。</p>\n<p>5.2 分销佣金规则详见《分销规则》，平台有权根据运营情况调整佣金比例。</p>\n<p>5.3 禁止通过虚假邀请、刷单等方式骗取佣金，一经发现将取消佣金并封禁账号。</p>\n<p><br/></p>\n<h3 style="color:#333;">六、知识产权</h3>\n<p>6.1 平台的所有内容（包括但不限于文字、图片、音频、视频、软件、界面设计等）均受知识产权法律保护。</p>\n<p>6.2 未经平台书面许可，您不得复制、传播、修改、创造衍生作品或进行商业使用。</p>\n<p><br/></p>\n<h3 style="color:#333;">七、免责声明</h3>\n<p>7.1 因不可抗力（如自然灾害、网络故障、政策变化等）导致服务中断的，平台不承担责任。</p>\n<p>7.2 因用户自身原因（如网络问题、设备故障等）导致无法使用服务的，平台不承担责任。</p>\n<p>7.3 平台提供的信息仅供参考，不构成任何投资建议或承诺。</p>\n<p><br/></p>\n<h3 style="color:#333;">八、协议终止</h3>\n<p>8.1 您可以随时注销账号并停止使用平台服务。注销后，账号内的金币、佣金等虚拟资产将被清零且不可恢复。</p>\n<p>8.2 如您严重违反本协议，平台有权单方面终止向您提供服务，并保留追究法律责任的权利。</p>\n<p><br/></p>\n<h3 style="color:#333;">九、其他条款</h3>\n<p>9.1 本协议的解释和执行适用中华人民共和国法律。</p>\n<p>9.2 如本协议中的任何条款被认定为无效或不可执行，不影响其他条款的效力。</p>\n<p>9.3 因本协议引起的争议，双方应友好协商解决；协商不成的，任何一方可向平台所在地有管辖权的人民法院提起诉讼。</p>\n<p><br/></p>\n<p style="color:#999;font-size:12px;text-align:right;">—— 平台运营团队</p>',
  'user-agreement',
  100,
  1,
  UNIX_TIMESTAMP(),
  UNIX_TIMESTAMP()
);

-- =====================================================
-- 隐私协议
-- =====================================================
INSERT INTO `advn_singlepage` (
  `category_id`, `title`, `keywords`, `description`,
  `image`, `content`, `tpl`, `weigh`, `status`,
  `createtime`, `updatetime`
) VALUES (
  @agreement_cat_id,
  '隐私协议',
  '隐私协议,隐私政策,个人信息保护,数据安全',
  '平台隐私保护政策',
  '',
  '<h2 style="text-align:center;color:#E62129;">隐私保护政策</h2>\n<p style="text-align:center;color:#999;font-size:12px;">更新日期：2026年7月17日</p>\n<p><br/></p>\n<p><b>平台深知个人信息对您的重要性，我们将按照法律法规的规定，保护您的个人信息及隐私安全。</b></p>\n<p>我们制定本《隐私保护政策》以帮助您了解我们如何收集、使用、存储和保护您的个人信息。请您在使用我们的服务前，仔细阅读并充分理解本政策。</p>\n<p><br/></p>\n<h3 style="color:#333;">一、我们收集的信息</h3>\n<p>1.1 <b>注册信息：</b>当您注册账号时，我们会收集您的手机号码、微信授权信息（昵称、头像等）。</p>\n<p>1.2 <b>个人资料：</b>当您完善个人资料时，我们会收集您设置的昵称、头像、性别、生日、个人简介等信息。</p>\n<p>1.3 <b>设备信息：</b>我们会自动收集您的设备型号、操作系统版本、设备标识符（IDFA/IMEI等）、IP地址、网络类型等信息，用于保障账号安全和优化服务体验。</p>\n<p>1.4 <b>行为信息：</b>我们会记录您在平台上的操作行为，包括但不限于签到记录、视频观看记录、提现记录、邀请关系等，用于提供服务和风控管理。</p>\n<p>1.5 <b>提现信息：</b>当您申请提现时，需要提供微信账户信息用于打款，该信息由微信平台处理，我们仅传递必要的打款指令。</p>\n<p><br/></p>\n<h3 style="color:#333;">二、我们如何使用您的信息</h3>\n<p>2.1 <b>提供核心服务：</b>用于账号注册、身份验证、金币发放与提现、邀请关系绑定等。</p>\n<p>2.2 <b>安全保障：</b>用于风控管理、防止作弊和欺诈行为、账号安全防护。</p>\n<p>2.3 <b>服务优化：</b>用于分析用户行为，优化产品功能和用户体验。</p>\n<p>2.4 <b>消息通知：</b>用于向您发送系统通知、活动通知等（您可以关闭推送通知）。</p>\n<p>2.5 <b>法律合规：</b>法律法规要求或监管部门要求的其他用途。</p>\n<p><br/></p>\n<h3 style="color:#333;">三、信息的存储与保护</h3>\n<p>3.1 <b>存储地点：</b>您的个人信息存储在中华人民共和国境内的服务器上。</p>\n<p>3.2 <b>存储期限：</b>我们仅在为您提供服务所必需的期限内保留您的个人信息。账号注销后，我们将删除或匿名化处理您的个人信息，法律法规另有规定的除外。</p>\n<p>3.3 <b>安全措施：</b>我们采用行业标准的安全技术措施保护您的信息，包括但不限于：</p>\n<ul>\n<li>SSL/TLS 加密传输；</li>\n<li>数据加密存储；</li>\n<li>严格的访问权限控制；</li>\n<li>定期的安全评估和审计。</li>\n</ul>\n<p>3.4 尽管我们采取了合理的安全措施，但互联网环境并非绝对安全。如发生个人信息安全事件，我们将及时通知您并采取补救措施。</p>\n<p><br/></p>\n<h3 style="color:#333;">四、信息的共享与披露</h3>\n<p>4.1 <b>我们不会向第三方出售您的个人信息。</b></p>\n<p>4.2 在以下情况下，我们可能会共享您的信息：</p>\n<ul>\n<li><b>服务合作伙伴：</b>如微信支付等，仅共享完成服务所必需的最少信息；</li>\n<li><b>法律要求：</b>根据法律法规、监管要求、诉讼或政府部门的合法要求；</li>\n<li><b>紧急情况：</b>为保护您或公众的人身、财产安全所必需。</li>\n</ul>\n<p>4.3 如发生合并、收购、资产转让等，我们会要求新的持有方继续受本隐私政策的约束。</p>\n<p><br/></p>\n<h3 style="color:#333;">五、您的权利</h3>\n<p>5.1 <b>查询权：</b>您可以在"个人资料"页面查看您的个人信息。</p>\n<p>5.2 <b>更正权：</b>您可以在"个人资料"页面修改您的昵称、头像、性别、生日、简介等信息。</p>\n<p>5.3 <b>删除权：</b>您可以申请注销账号，注销后我们将删除您的个人信息（法律法规要求保留的除外）。</p>\n<p>5.4 <b>撤回同意权：</b>您可以在设备设置中关闭相关权限（如位置、相册等），这可能影响部分功能的使用。</p>\n<p>5.5 <b>投诉权：</b>如您对我们的个人信息处理有任何疑问或投诉，可以通过平台客服渠道联系我们。</p>\n<p><br/></p>\n<h3 style="color:#333;">六、未成年人保护</h3>\n<p>6.1 我们非常重视未成年人的个人信息保护。</p>\n<p>6.2 如果您是未满18周岁的未成年人，请在监护人的陪同下阅读本政策，并在取得监护人同意后使用我们的服务。</p>\n<p>6.3 我们不会主动收集未满14周岁儿童的个人信息。如我们发现在未取得监护人同意的情况下收集了儿童信息，将及时删除。</p>\n<p><br/></p>\n<h3 style="color:#333;">七、Cookie 和类似技术</h3>\n<p>7.1 我们使用 Cookie 和类似技术来改善您的使用体验，例如记住您的登录状态。</p>\n<p>7.2 您可以通过浏览器设置拒绝或删除 Cookie，但这可能影响您使用平台的部分功能。</p>\n<p><br/></p>\n<h3 style="color:#333;">八、隐私政策的更新</h3>\n<p>8.1 我们可能会不时更新本隐私政策。更新后的政策将在平台内公布。</p>\n<p>8.2 如变更内容对您的权利产生重大影响，我们会通过弹窗、站内信等方式显著通知您。</p>\n<p>8.3 在您继续使用我们的服务后，即视为同意受更新后的隐私政策约束。</p>\n<p><br/></p>\n<h3 style="color:#333;">九、联系我们</h3>\n<p>如您对本隐私政策有任何疑问、意见或建议，可通过以下方式联系我们：</p>\n<ul>\n<li>在App内联系在线客服；</li>\n<li>发送邮件至平台客服邮箱。</li>\n</ul>\n<p><br/></p>\n<p style="color:#999;font-size:12px;text-align:right;">—— 平台运营团队</p>',
  'privacy-policy',
  90,
  1,
  UNIX_TIMESTAMP(),
  UNIX_TIMESTAMP()
);
